import { Action, ActionPanel, Clipboard, Detail, Form, Icon, getPreferenceValues, showToast, Toast, useNavigation } from "@raycast/api";
import { useState } from "react";

interface Preferences {
  taxRate: string;
  ownerRate: string;
  opexRate: string;
}

interface Breakdown {
  amount: number;
  taxRate: number;
  ownerRate: number;
  opexRate: number;
  tax: number;
  owner: number;
  opex: number;
}

const currency = new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" });

function parseRate(value: string, fallback: number): number {
  const n = Number.parseFloat(value);
  return Number.isFinite(n) ? n : fallback;
}

function buildMarkdown(b: Breakdown): string {
  return `# Income Breakdown

**Payment:** ${currency.format(b.amount)}

| Bucket | Rate | Amount |
| --- | ---: | ---: |
| Taxes | ${b.taxRate}% | ${currency.format(b.tax)} |
| Owner | ${b.ownerRate}% | ${currency.format(b.owner)} |
| Operating Expenses | ${b.opexRate}% | ${currency.format(b.opex)} |
| **Total** | **${b.taxRate + b.ownerRate + b.opexRate}%** | **${currency.format(b.tax + b.owner + b.opex)}** |
`;
}

function ResultView({ breakdown }: { breakdown: Breakdown }) {
  const plain = [
    `Payment: ${currency.format(breakdown.amount)}`,
    `Taxes (${breakdown.taxRate}%): ${currency.format(breakdown.tax)}`,
    `Owner (${breakdown.ownerRate}%): ${currency.format(breakdown.owner)}`,
    `Operating Expenses (${breakdown.opexRate}%): ${currency.format(breakdown.opex)}`,
  ].join("\n");

  return (
    <Detail
      markdown={buildMarkdown(breakdown)}
      actions={
        <ActionPanel>
          <Action.CopyToClipboard title="Copy Full Breakdown" content={plain} />
          <Action.CopyToClipboard title="Copy Taxes Amount" content={breakdown.tax.toFixed(2)} />
          <Action.CopyToClipboard title="Copy Owner Amount" content={breakdown.owner.toFixed(2)} />
          <Action.CopyToClipboard title="Copy Operating Amount" content={breakdown.opex.toFixed(2)} />
        </ActionPanel>
      }
    />
  );
}

export default function Command() {
  const prefs = getPreferenceValues<Preferences>();
  const taxRate = parseRate(prefs.taxRate, 30);
  const ownerRate = parseRate(prefs.ownerRate, 60);
  const opexRate = parseRate(prefs.opexRate, 10);

  const { push } = useNavigation();
  const [amountError, setAmountError] = useState<string | undefined>();

  async function handleSubmit(values: { amount: string }) {
    const amount = Number.parseFloat(values.amount.replace(/[$,\s]/g, ""));
    if (!Number.isFinite(amount) || amount < 0) {
      setAmountError("Enter a valid amount");
      return;
    }

    const breakdown: Breakdown = {
      amount,
      taxRate,
      ownerRate,
      opexRate,
      tax: amount * (taxRate / 100),
      owner: amount * (ownerRate / 100),
      opex: amount * (opexRate / 100),
    };

    if (taxRate + ownerRate + opexRate !== 100) {
      await showToast({
        style: Toast.Style.Failure,
        title: "Rates don't add up to 100%",
        message: `Currently ${taxRate + ownerRate + opexRate}%. Check the extension preferences.`,
      });
    }

    await Clipboard.copy(breakdown.owner.toFixed(2));
    push(<ResultView breakdown={breakdown} />);
  }

  return (
    <Form
      actions={
        <ActionPanel>
          <Action.SubmitForm title="Calculate" icon={Icon.Calculator} onSubmit={handleSubmit} />
        </ActionPanel>
      }
    >
      <Form.Description text={`Taxes ${taxRate}% · Owner ${ownerRate}% · Operating ${opexRate}%`} />
      <Form.TextField
        id="amount"
        title="Payment Amount"
        placeholder="e.g. 5000"
        autoFocus
        error={amountError}
        onChange={() => amountError && setAmountError(undefined)}
      />
    </Form>
  );
}
